        self.card_holder_name = card_holder_name
        self.card_expiration_date = card_expiration_date
        self.issuing_bank = issuing_bank
        self.card_type = card_type
        self.country_code = country_code
        self.amount = amount
        self.approval_code = approval_code
        self.cvv = cvv

    def process_transaction(self):
        if self.validate_transaction():
            return self.authorize_transaction()
        return "Transaction Failed"

    def validate_transaction(self):
        if len(self.card_number) == 16 and self.card_expiration_date and self.cvv:
            return True
        return False

    def authorize_transaction(self):
        return f"Transaction Approved. Approval Code: {self.approval_code}"

